const tagContainer=document.getElementById("tag-container");fetch("/api/tags?sort=post_count&order=desc").then(t=>{t.json().then(t=>{t.data.forEach(t=>{if(t.post_count>0&&"banned"!=t.type){var e=document.createElement("li"),n=document.createElement("a"),a=document.createElement("div");n.href=`/posts/?tags=${t.name}`,n.innerText=t.name,a.innerText=t.post_count,n.classList.add("tag-list-item"),e.classList.add(t.type),e.appendChild(n),e.appendChild(a),e.onclick=function(e){location.href=`/posts/?tags=${t.name}`},tagContainer.appendChild(e)}})})});